```json
{
  "global": "Navigate to a gaming information website, locate upcoming game releases, sort by popularity, and extract the ranked list.",
  "subtasks": [
    {
      "subtask": "Locate and open a gaming information website with upcoming releases data",
      "atomics": [
        "Search for or navigate to a gaming information website (IGN, GameSpot, IGDB, Metacritic)",
        "Load the website homepage",
        "Ensure navigation menu is visible and clickable"
      ]
    },
    {
      "subtask": "Navigate to the upcoming game releases section",
      "atomics": [
        "Scan page navigation for upcoming releases or coming soon section",
        "Click on the upcoming releases link",
        "Wait for upcoming games page to load"
      ]
    },
    {
      "subtask": "Sort or filter results by popularity metrics",
      "atomics": [
        "Locate sort/filter controls on results page",
        "Select popularity-based sort (most anticipated, most hyped, most wishlisted)",
        "Apply sort and refresh results"
      ]
    },
    {
      "subtask": "Extract and present the list of popular upcoming games",
      "atomics": [
        "Identify game entries in sorted results",
        "Extract game title, release date, and popularity score for each game",
        "Format and display as ranked list by popularity"
      ]
    }
  ],
  "global_atomics": [
    "Verify all games in results have future release dates",
    "Confirm results contain sufficient number of games (5+ entries)"
  ],
  "gold_actions": {
    "global": "Visit IGDB or similar gaming database, access upcoming releases, sort by player anticipation or hype score, and extract ranked list of most popular upcoming game titles with release dates.",
    "subtasks": [
      {
        "subtask": "Open IGDB or equivalent gaming database website",
        "atomics": [
          "Navigate browser to https://www.igdb.com or similar gaming site",
          "Wait for website and navigation menu to fully load"
        ]
      },
      {
        "subtask": "Access the upcoming game releases section",
        "atomics": [
          "Identify 'Upcoming Games' or 'Coming Soon' link in main navigation",
          "Click upcoming games navigation link",
          "Wait for upcoming releases results page to load"
        ]
      },
      {
        "subtask": "Apply anticipation or hype-based sorting to results",
        "atomics": [
          "Find sort dropdown menu on results page",
          "Select 'Most Anticipated' or 'Most Hyped' sorting option",
          "Apply sort and wait for results to update"
        ]
      },
      {
        "subtask": "Extract game information and format output list",
        "atomics": [
          "Locate each game title card or entry in sorted results",
          "Scrape game name, release date, and anticipation/hype score from each entry",
          "Format games into ordered list ranked by popularity metric"
        ]
      }
    ],
    "gold_atomics": [
      "Verify each game result has a release date in the future (>= current date)",
      "Confirm final list contains minimum 5-10 game titles with complete name and date information"
    ]
  }
}
